head.script:
//==================================================================================================================
// id       : co_201_06_01b
// 이름     : 매출계획시뮬레이션
// 경로     : 회계/관리회계/사업계획/
// 작 성 자 : 오영재
// 작 업 일 : 
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.gus.cfIsNull(scwin.memJson.privAdmin) ? '' : scwin.memJson.privAdmin;
scwin.today = $c.date.getServerDateTime("yyyyMMdd");

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;   //소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;   //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson.userHomeClsCd) ? '' : scwin.memJson.userHomeClsCd;   //사용자소속구분코드
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;   //회사코드
scwin.isSubCompany = false;

//hidden
scwin.txtCoClsCd = "";

scwin.strFromDate = scwin.today.substring(0,4);

scwin.onpageload = function() {
	const codeOptions = [
         { grpCd : "CO015", compID : "gr_primecost:varFixedClsCd,gr_export:varFixedClsCd" }  // 통화코드
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableKey();
    scwin.f_FieldClear();
    scwin.f_setCompanyInfo();

    //2026.04.02 자회사이면 회사코드 검색 창 비활성화
    if (scwin.vUserHomeClsCd == ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        $c.gus.cfDisableObjects([udc_coCd]);
    }
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search,[ed_srchPlanYr]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
    $c.gus.cfInitHidVal(tbl_search);
    ed_srchPlanYr.setValue( scwin.today.substring(0,4) );
    //디버그용
    // ed_srchRsltsStYm.setValue( "202001" );
    // ed_srchRsltsEndYm.setValue( "202001" );

    // ed_srchTermStYm.setValue( "202002" );
    // ed_srchTermEndYm.setValue( "202002" );

    //ed_srchAcctDeptCd.setValue( "00050" );
    //ed_srchAcctDeptNm.setValue( "부산운송" );

    scwin.f_GetVersion();
    ed_srchPlanYr.focus();
}

scwin.sbm_version_submitdone = function(e) {
    scwin.f_SetFinalVer();
}
scwin.sbm_version_submiterror = function(e) {}

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function() {
    if (ds_version.getRowCount() < 1) return;

    let index = 0;
    for (i=0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == "1") {
            index = i;
            break;
        }
    }

    lc_version.setSelectedIndex(index);
}

//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function() {
    sbm_version.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
                                            "&queryId=retrieveVersionInfo" +
                                            "&param1=" + ed_srchPlanYr.getValue().trim() + "00";
    //ds_version.Reset();
    $c.sbm.execute(sbm_version);
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function(){   
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue( scwin.vLoginCoCd );
    scwin.f_PopUpCompanyInfo('T', ed_coCd, ed_coNm);

    if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_schCompany ]);    
    } else {
        $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_schCompany  ]);   
    }  
}    

scwin.udc_coCd_cb = function(rtnList) {
    // SET
    if(rtnList != null ) { 

    if (rtnList[0] == "N/A") return; 
        ed_coCd.setValue( rtnList[0] );	// 코드
        ed_coNm.setValue( rtnList[5] ); // 회사명 
        scwin.txtCoClsCd = rtnList[1];	// 회사구분   
    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
    }

    if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    }
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF, _coCd, _coNm) {
    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    udc_coCd.cfCommonPopUp(
        scwin.udc_coCd_cb
            ,_coCd.getValue(), _coNm.getValue()
            ,pWinCloseTF,null,null,null,null
            ,null,null,null,null,null);   
}  

scwin.btn_reset_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_search_onclick = function (e) {
    scwin.f_PreRetrieve();
};

scwin.btn_apply_onclick = function (e) {
    scwin.f_ProcPlanChange();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
//if (f_IsDataUpdated([ds_selling, ds_primecost, ds_grossmargin])) {
//  if(cfConfirmMsg(MSG_CM_CRM_005) == false) return;
//}

//if (!cfValidate([tbl_search])) return false;

    //ds_search.UseChangeInfo = false;
    //tr_search.post();

    dma_search.set("ver", lc_version.getValue());
    dma_search.set("planYr", ed_srchPlanYr.getValue());
    dma_search.set("acctDeptCd", ed_srchAcctDeptCd.getValue());
    dma_search.set("rsltsStYm", ed_srchRsltsStYm.getValue());
    dma_search.set("rsltsEndYm", ed_srchRsltsEndYm.getValue());
    dma_search.set("termStYm", ed_srchTermStYm.getValue());
    dma_search.set("termEndYm", ed_srchTermEndYm.getValue());
    dma_search.set("rasingRt", ed_rasingRt.getValue());
    dma_search.set("coCd", ed_coCd.getValue());
    dma_search.set("coNm", ed_coNm.getValue());

    $c.sbm.execute(sbm_search);
}

scwin.sbm_search_submitdone = function(e) {
    if( ds_selling.getRowCount() == 0 ){
       if($c.gus.cfCheckCreateFlag() == true){
            $c.gus.cfTurnCreateFlag(false);
       }else{
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
       }
    } else {

        var options = {};
        options.sortIndex = "varFixedClsCd mgntAcctCd";
        options.sortOrder = "1 1";     //오른차순:"1", 내림차순"-1"
        ds_primecost.multisort(options);
        ds_primecost.reform();

        ed_rasingRt.setValue( ds_selling.getCellData(0, "rasingRt") );
    }    
}
scwin.sbm_search_submiterror = function(e) {}

scwin.sbm_master_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        /** AsIs는 재조회 없이도 갱신이 되고 있다. 리폼으로도 되긴 하는데 다른 화면들이 조회
        ds_selling.reform();
        ds_primecost.reform();
        ds_grossmargin.reform();
        */
        await $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
}
scwin.sbm_master_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
}

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(){
    let ret;
    if(ds_selling.getRowCount() < 1){
        $c.gus.cfAlertMsg("조회된 자료가 없습니다.");
    } else {
        ret = await $c.win.confirm(MSG_CM_CRM_001);
        if(ret){
            //고정비 인상율을 설정
            scwin.f_SetDatasetValue(gr_selling, ds_selling, "rasingRt",($c.gus.cfIsNull(ed_rasingRt) ? 0 : ed_rasingRt.getValue()));
            scwin.f_SetDatasetValue(gr_primecost, ds_primecost, "rasingRt",($c.gus.cfIsNull(ed_rasingRt) ? 0 : ed_rasingRt.getValue()));
            scwin.f_SetDatasetValue(gr_grossmargin, ds_grossmargin, "rasingRt",($c.gus.cfIsNull(ed_rasingRt) ? 0 : ed_rasingRt.getValue()));

            // ds_selling.UseChangeInfo = false;
            // ds_primecost.UseChangeInfo = false;
            // ds_grossmargin.UseChangeInfo = false;
            //tr_master.post();
            $c.sbm.execute(sbm_master);
        }
    }
}

//-------------------------------------------------------------------------
// 데이터셋의 자료 변경 여부를 반환 :
//-------------------------------------------------------------------------
scwin.f_IsDataUpdated = function(dataSetArray) {
    if (dataSetArray == null) return false;
    for (var i=0; i < dataSetArray.length; i++) {
        if (dataSetArray[i].getModifiedIndex().length > 0) return true;
    }
    return false;
}

//-------------------------------------------------------------------------
// Array 여부를 반환
//-------------------------------------------------------------------------
scwin.f_IsArray = function(inObj) {
    return (inObj instanceof Array);
}

//-------------------------------------------------------------------------
// 코드와 Hidden 값이 같은 지 여부를 반환
//-------------------------------------------------------------------------
