//-------------------------------------------------------------------------
// 사전 조회 팝업
//-------------------------------------------------------------------------
scwin.f_PreRetrieve = async function() {

    let ret;
    if (scwin.f_IsDataUpdated([ds_selling, ds_primecost, ds_grossmargin])) {
        ret = await $c.win.confirm(MSG_CM_CRM_005); 
        if(ret == false) return;
    }

    ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret) return;

    //if (!scwin.f_checkHidVal([ed_srchAcctDeptCd])) return false;
    if (ed_srchAcctDeptCd.getValue() != ed_srchAcctDeptCd.options.hidVal ) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["부서"]);
        return false;

    }


    //ds_preSrch.Reset();
    sbm_preSrch.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
                                            "&queryId=retrieveSellSimulationInfo" +
                                            "&param1=" + ed_srchAcctDeptCd.getValue() +
                                            "&param2=" + ed_srchAcctDeptNm.getValue() +
                                            "&param3=" + lc_version.getValue() +
                                            "&param4=" + ed_srchPlanYr.getValue() +
                                            "&param5=" + ed_srchRsltsStYm.getValue() +
                                            "&param6=" + ed_srchRsltsEndYm.getValue() +
                                            "&param7=" + ed_srchTermStYm.getValue() +
                                            "&param8=" + ed_srchTermEndYm.getValue()
                        ;
    $c.sbm.execute(sbm_preSrch);
}

//-------------------------------------------------------------------------
// Object의 값이 없는지 여부를 반환
//-------------------------------------------------------------------------
scwin.f_IsEmpty = function(inObj) {
    return $c.gus.cfIsNull($c.gus.cfGetValue(inObj));
}

//-------------------------------------------------------------------------
// 두 월(YYYYMM)을 비교
//-------------------------------------------------------------------------
scwin.f_IsAfterMonth = function(startMonth, endMonth, exceptSame) {
    return $c.gus.cfIsAfterDate(startMonth + '01', endMonth + '01', exceptSame)
}

//-------------------------------------------------------------------------
// 필수 입력 외의 조회조건을 검증
//-------------------------------------------------------------------------
scwin.f_ValidateOptional = function() {
    if (scwin.f_IsEmpty(ed_srchRsltsStYm)) {
        $c.gus.cfAlertMsg("실적기간을 입력해 주십시요.");
        ed_srchRsltsStYm.focus();
        return false;
    }
    if (scwin.f_IsEmpty(ed_srchRsltsEndYm)) {
        $c.gus.cfAlertMsg("실적기간을 입력해 주십시요.");
        ed_srchRsltsEndYm.focus();
        return false;
    }

    if (!scwin.f_IsAfterMonth(ed_srchRsltsStYm.getValue(), ed_srchRsltsEndYm.getValue())) {
        $c.gus.cfAlertMsg("실적기간의 범위가 잘못되었습니다.");
        ed_srchRsltsStYm.focus();
        return false;
    }

    if (scwin.f_IsEmpty(ed_srchTermStYm)) {
        $c.gus.cfAlertMsg("추정기간을 입력해 주십시요.");
        ed_srchTermStYm.focus();
        return false;
    }
    if (scwin.f_IsEmpty(ed_srchTermEndYm)) {
        $c.gus.cfAlertMsg("추정기간을 입력해 주십시요.");
        ed_srchTermEndYm.focus();
        return false;
    }
    if (!scwin.f_IsAfterMonth(ed_srchTermStYm.getValue(), ed_srchTermEndYm.getValue())) {
        $c.gus.cfAlertMsg("추정기간의 범위가 잘못되었습니다.");
        ed_srchTermStYm.focus();
        return false;
    }

    return true;
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_SetSrchOption = function(rsltsStYm, rsltsEndYm, termStYm, termEndYm) {
    $c.gus.cfSetValue(ed_srchRsltsStYm, rsltsStYm);
    $c.gus.cfSetValue(ed_srchRsltsEndYm, rsltsEndYm);
    $c.gus.cfSetValue(ed_srchTermStYm, termStYm);
    $c.gus.cfSetValue(ed_srchTermEndYm, termEndYm);
}

scwin.sbm_preSrch_submitdone = function(e) {
    let rowCnt = ds_preSrch.getRowCount();
    if( rowCnt == 0 ){
        if (scwin.f_ValidateOptional()) {
            scwin.f_Retrieve();
        }
    } else if( rowCnt == 1 ) {
        scwin.f_SetSrchOption(
                        ds_preSrch.getCellData(0, "col3").split("~")[0]
                      , ds_preSrch.getCellData(0, "col3").split("~")[1]
                      , ds_preSrch.getCellData(0, "col4").split("~")[0]
                      , ds_preSrch.getCellData(0, "col4").split("~")[1]);
        scwin.f_Retrieve();
    } else {
        scwin.f_srchPopUp();
    }
}
scwin.sbm_preSrch_submiterror = function(e) {}

scwin.udc_srchAcctDeptCd_cb = function(rtnList) {
    if (rtnList == null || rtnList[0] == 'N/A') {
        $c.gus.cfAlertMsg("조회 대상이 없거나 선택하지 않았습니다.");
        return false;
        //if (f_ValidateOptional() == false) return;
    } else {
        scwin.f_SetSrchOption(rtnList[2].substring(0,6)
                        , rtnList[2].substring(7,6)
                        , rtnList[3].substring(0,6)
                        , rtnList[3].substring(7,6));
    }
}

scwin.udc_srchAcctDeptCd_cb2 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_srchAcctDeptCd, ed_srchAcctDeptNm);
}

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_CallCommonPopUp = function(paramArray) {
    if ($c.gus.cfIsNull(paramArray.pCode)) paramArray.pCode = "";
    if ($c.gus.cfIsNull(paramArray.pName)) paramArray.pName = "";

    if (paramArray.flag == "1") {
        udc_srchAcctDeptCd.setSelectId( paramArray.pSelectID );
        udc_srchAcctDeptCd.cfCommonPopUp(
            scwin.udc_srchAcctDeptCd_cb
            , paramArray.pCode, paramArray.pName
                                ,paramArray.pWinCloseTF, paramArray.pDispCnt
                                ,paramArray.pTitle, paramArray.pWidth
                                ,paramArray.pHidden, paramArray.pWhere
                                ,paramArray.pW, paramArray.pH
                                ,paramArray.pTop, paramArray.pLeft
                                ,paramArray.pExistTF, paramArray.pAllSearchTF
                                ,paramArray.pWtitleSearch);
    } else if (paramArray.flag == "2") {
        udc_srchAcctDeptCd.setSelectId( paramArray.pSelectID );
        udc_srchAcctDeptCd.cfCommonPopUp(
            scwin.udc_srchAcctDeptCd_cb2
            , paramArray.pCode, paramArray.pName
                                ,paramArray.pWinCloseTF, paramArray.pDispCnt
                                ,paramArray.pTitle, paramArray.pWidth
                                ,paramArray.pHidden, paramArray.pWhere
                                ,paramArray.pW, paramArray.pH
                                ,paramArray.pTop, paramArray.pLeft
                                ,paramArray.pExistTF, paramArray.pAllSearchTF
                                ,paramArray.pWtitleSearch);
    }

}

//-------------------------------------------------------------------------
// 사전 조회 팝업
//-------------------------------------------------------------------------
scwin.f_srchPopUp = function() {
    let codeObj = ed_srchAcctDeptCd;
    let nameObj = ed_srchAcctDeptNm;

    let paramArray = {
        "flag" : "1",
        "pSelectID" : "retrieveSellSimulationInfo",
        "pCode" : $c.gus.cfGetValue(codeObj),
        "pName" : $c.gus.cfGetValue(nameObj),
        "pWinCloseTF" : "T",
        "pWhere" : lc_version.getValue() + ',' + ed_srchPlanYr.getValue(),
    }

    scwin.f_CallCommonPopUp(paramArray);
    f_Retrieve();
}

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function(pWinCloseTF) {
    let codeObj = ed_srchAcctDeptCd;
    let nameObj = ed_srchAcctDeptNm;

    let paramArray = {
        "flag" : "2",
        "pSelectID" : "retrieveAcctDeptCdInfo",
        "pCode"     : $c.gus.cfGetValue(codeObj),
        "pName"     : $c.gus.cfGetValue(nameObj),
        "pWinCloseTF" : pWinCloseTF,
        "pWhere"    : ed_srchPlanYr.getValue()+",,,,,,,,,"+ed_coCd.getValue()  //예산년도 파람메터추가 ejsong9
    }

    scwin.f_CallCommonPopUp(paramArray);
}

//----------------------------------------------------------------산---------
// 비율을 이용해서 금액을 계산
//-------------------------------------------------------------------------
scwin.f_CalcAmtByRate = function(dataSet, baseAmt, rateColumn, amtColumn){
    try {
        if (dataSet == null || dataSet.getRowCount() < 1)  throw "대상 데이터셋이 정의되지 않았습니다.";
        if (baseAmt == null || baseAmt == 0) throw "기준금액이 정의되지 않았습니다.";
        if (rateColumn == null) throw "비율 컬럼이 정의되지 않았습니다.";
        if (amtColumn == null) throw "금액 컬럼이 정의되지 않았습니다.";

        for (var i=0; i < dataSet.getRowCount(); i++) {
            dataSet.setCellData(i, amtColumn, Math.round((dataSet.getCellData(i, rateColumn)/100) * baseAmt) );
        }
    } catch (e) {
        $c.gus.cfAlertMsg(e);
    }
}

//-------------------------------------------------------------------------
// 두 컬럼의 합을 계산
//-------------------------------------------------------------------------
scwin.f_AddColumnValue = function(dataSet, sourceColumns, targetColumn) {
    try {
        if (dataSet == null || dataSet.getRowCount() < 1)  throw "대상 데이터셋이 정의되지 않았습니다.";
        if (sourceColumns == null) throw "대상 컬럼이 정의되지 않았습니다.";
        if (targetColumn == null) throw "결과 컬럼이 정의되지 않았습니다.";
        let result = 0;
        for (var i=0; i < dataSet.getRowCount(); i++) {
            for (var j=0; j < sourceColumns.length; j++) {
                result += Number(dataSet.getCellData(i, sourceColumns[j]));
            }
            dataSet.setCellData(i, targetColumn, result);
            result = 0;
        }
    } catch (e) {
        $c.gus.cfAlertMsg(e);
    }
}

//-------------------------------------------------------------------------
// 비율을 이용해서 금액을 계산
//-------------------------------------------------------------------------
scwin.f_CalcRateByAmt = function(dataSet, baseAmt, amtColumn, rateColumn){
    try {
        if (dataSet == null || dataSet.getRowCount() < 1)  throw "대상 데이터셋이 정의되지 않았습니다.";
        if (baseAmt == null || baseAmt == 0) throw "기준금액이 정의되지 않았습니다.";
        if (amtColumn == null) throw "금액 컬럼이 정의되지 않았습니다.";
        if (rateColumn == null) throw "비율 컬럼이 정의되지 않았습니다.";

        for (var i=0; i < dataSet.getRowCount(); i++) {
            dataSet.setCellData(i, rateColumn, scwin.f_RoundEx((dataSet.getCellData(i, amtColumn)/baseAmt)* 100, 2) );
        }
    } catch (e) {
        $c.gus.cfAlertMsg(e);
    }
}

//-------------------------------------------------------------------------
// Math.round 함수 확장
//-------------------------------------------------------------------------
scwin.f_RoundEx = function(num, pos) {
    try {
        if (num == null)  throw "Rounding Number가 정의되지 않았습니다.";
        if (pos == null) pos = 0;
        if (pos < 0) throw "소수점 이하 자리는 0이상이어야 합니다.";

        let temp = "1";
        for (var i=0; i < pos; i++) {
            temp += "0";
        }

        let shift = Number(temp);
        return (Math.round(num * shift) / shift);
    } catch (e) {
        $c.gus.cfAlertMsg(e);
    }
}

//-------------------------------------------------------------------------
// 추정금액 변경 처리
//-------------------------------------------------------------------------
scwin.f_ProcPresumeChange = function(){
    if (ds_selling.getRowCount() < 1) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let row = ds_selling.getRowPosition();
    let baseAmt = ds_selling.getCellData(row, "presumeAmt");

    if ($c.gus.cfIsNull(baseAmt) || baseAmt <= 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["추정 매출액", "1"]);
        return;
    }

    //추정금액 계산
    scwin.f_CalcAmtByRate(ds_primecost,baseAmt,"presumeRt","presumeAmt");     //매출원가
    scwin.f_CalcAmtByRate(ds_grossmargin,baseAmt,"presumeRt","presumeAmt");   //총이익

    //합계금액 계산
    scwin.f_AddColumnValue(ds_selling,["rsltsAmt","presumeAmt"],"sumAmt");        //매출
    scwin.f_AddColumnValue(ds_primecost,["rsltsAmt","presumeAmt"],"sumAmt");      //매출원가
    scwin.f_AddColumnValue(ds_grossmargin,["rsltsAmt","presumeAmt"],"sumAmt");    //총이익

    //합계비율 계산
    scwin.f_CalcRateByAmt(ds_primecost,ds_selling.getCellData(row,"sumAmt"),"sumAmt","sumRt");   //매출원가
    scwin.f_CalcRateByAmt(ds_grossmargin,ds_selling.getCellData(row,"sumAmt"),"sumAmt","sumRt"); //총이익
}

//-------------------------------------------------------------------------
// 고정비인상율을 계획비율에 더한다.
//-------------------------------------------------------------------------
scwin.f_IsFixedCost = function(costClsCd){
    return (costClsCd == ACConstants.VARFIXED_COST_CLS_FIXED);
}

//-------------------------------------------------------------------------
// 계획금액 변경 처리
//-------------------------------------------------------------------------
scwin.f_ProcPlanChange = function(){
    if (ds_selling.getRowCount() < 1) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let row = ds_selling.getRowPosition();
    let baseAmt = ds_selling.getCellData(row, "planAmt");

    if ($c.gus.cfIsNull(baseAmt) || baseAmt <= 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["계획 매출액", "1"]);
        return;
    }

    ds_selling.setCellData(row, "planRt", 100);
    sellingAmt = ds_selling.getCellData(row, "rsltsAmt"); //매출액 실적
    rasingRt = ($c.gus.cfIsNull(ed_rasingRt.getValue()) ? 0 : ed_rasingRt.getValue());

    for (var i=0; i < ds_primecost.getRowCount(); i++) {
        if (scwin.f_IsFixedCost(ds_primecost.getCellData(i, "varFixedClsCd"))) {
            //고정비 계획 금액을 계산하고 계획비율을 계산
            ds_primecost.setCellData(i,"planAmt", Math.round(ds_primecost.getCellData(i,"rsltsAmt") * (1 + rasingRt/100)) );
            ds_primecost.setCellData(i,"planRt", scwin.f_RoundEx(ds_primecost.getCellData(i,"planAmt") / baseAmt * 100, 2) );
        } else {
            //변동비 실적 비율을 계획 변동비 비율로 복사하고 계획금액을 계산
            ds_primecost.setCellData(i,"planRt", ds_primecost.getCellData(i,"rsltsRt") );
            ds_primecost.setCellData(i,"planAmt", Math.round(baseAmt * ds_primecost.getCellData(i,"planRt") / 100) );
        }
    }

    //매출총이익 계산
    let sumPlanAmt = 0;
    for (i = 0; i<ds_primecost.getRowCount(); i++) {
        sumPlanAmt += Number(ds_primecost.getCellData(i, "planAmt"));
    }
    ds_grossmargin.setCellData(row, "planAmt", baseAmt - sumPlanAmt ) ;
    ds_grossmargin.setCellData(row, "planRt", scwin.f_RoundEx(ds_grossmargin.getCellData(row, "planAmt") / baseAmt * 100, 2) );
}

//----------------------------------------------------------------산---------
// 비율을 이용해서 금액을 계산
//-------------------------------------------------------------------------
scwin.f_SetDatasetValue = function(grid, dataSet, column, value){
    try {
        if (grid == null || dataSet.getRowCount() < 1)  throw "대상 그리드가 정의되지 않았습니다.";
        if (dataSet == null || dataSet.getRowCount() < 1)  throw "대상 데이터셋이 정의되지 않았습니다.";
        if (column == null) throw "컬럼이 정의되지 않았습니다.";
        if (value == null) throw "컬럼에 설정할 값이 정의되지 않았습니다.";

        //grid.Redraw = "false";
        for (var i=0; i < dataSet.getRowCount(); i++) {
            dataSet.setCellData(i, column, value);
        }
        //grid.Redraw = "true";
    } catch (e) {
        $c.gus.cfAlertMsg(e);
    }
}

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Export = function(){
    if(ds_selling.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    //엑셀다운 데이터셋 초기화
    ds_export.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_primecost, ds_export);

    //매출액 복사
    //scwin.f_CopyDataRow(ds_selling, ds_export, ds_selling.getRowPosition());
    scwin.f_CopyDataRow(ds_selling, ds_export, 0);
    ds_export.setCellData(ds_export.getRowPosition(), "varFixedClsCd", "");

    //매출원가복사
    //var subsumExpr = ds_primecost.SubsumExpr;
    //var sortExpr = ds_primecost.SortExpr;
    //ds_primecost.SubsumExpr = "";
    //ds_primecost.SortExpr = "";
    for (var i=0; i < ds_primecost.getRowCount(); i++) {
        scwin.f_CopyDataRow(ds_primecost, ds_export, i);
    }
    //ds_primecost.SubsumExpr = subsumExpr;
    //ds_primecost.SortExpr = sortExpr;

    //매출총이익복사
    //scwin.f_CopyDataRow(ds_grossmargin, ds_export, ds_grossmargin.getRowPosition());
    scwin.f_CopyDataRow(ds_grossmargin, ds_export, 0);
    ds_export.setCellData(ds_export.getRowPosition(), "varFixedClsCd", "");

    //Subsum Row 삭제
    for (var i=0; i < ds_export.getRowCount(); i++) {
        if ($c.gus.cfIsNull(ds_export.getCellData(i, "mgntAcctNm"))) {
            ds_export.deleteRow( i );  
        }
    }

    let sheetTitle = '매출계획시뮬레이션_' + ed_srchPlanYr.getValue() + "_" + $c.gus.cfGetValue(lc_version)
                + "_" + $c.gus.cfGetValue(ed_srchAcctDeptNm);
	const gridId = gr_export;
	const infoArr = [];
	const options = {
		fileName: sheetTitle + ".xlsx",    // + ".xls",
		sheetName: sheetTitle
	};

	$c.data.downloadGridViewExcel(gridId, options, infoArr);
}

//-------------------------------------------------------------------------
// 데이터셋 Row 복사
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function(sourceDataset, targetDataset, sourceRow, targetRow, sourceColumns, targetColumns, actionAfterRowAdded) {
    try {
        if (sourceDataset == null) throw "원본 데이터셋이 정의되지 않았습니다.";
        if (targetDataset == null) throw "대상 데이터셋이 정의되지 않았습니다.";

        if (sourceColumns == null) sourceColumns = scwin.f_GetColumnNames(sourceDataset);
        if (targetColumns == null) targetColumns = sourceColumns;
        if (sourceRow == null) sourceRow = sourceDataset.getRowPosition();
        if (targetRow == null) targetRow = scwin.f_AddRowEx(targetDataset);

        //console.log("sourceRow =>" + sourceRow);
        //console.log("targetRow =>" + targetRow);

        for (var i=0; i < sourceColumns.length; i++) {
            if ($c.gus.cfIsNull(sourceColumns[i]) || $c.gus.cfIsNull(targetColumns[i])) continue;
            targetDataset.setCellData(targetRow,targetColumns[i], sourceDataset.getCellData(sourceRow,sourceColumns[i]) );
            if (actionAfterRowAdded != null) actionAfterRowAdded;
        }
        return targetRow;
    } catch (e) {
        $c.gus.cfAlertMsg("[f_CopyDataRow]" + e);
    }
}

//-------------------------------------------------------------------------
// 데이터셋의 행을 추가하고 RowPosition을 반환
//-------------------------------------------------------------------------
scwin.f_AddRowEx = function(dataSet){
    let row = dataSet.insertRow();
    dataSet.setRowPosition(row);

    return dataSet.getRowPosition();
}

//-------------------------------------------------------------------------
// 데이터셋의 모든 컬럼명을 배열로 반환
//-------------------------------------------------------------------------
scwin.f_GetColumnNames = function(dataSet) {
    try {
        if (dataSet == null) throw "데이터셋이 정의되지 않았습니다.";
        if (dataSet.getTotalCol() == 0) return null;

        let rtnArray = new Array(dataSet.getTotalCol());

        for (var i=0; i < dataSet.getTotalCol(); i++) {
            rtnArray[i] = dataSet.getColumnID(i);
        }

        if (rtnArray.length == 0)
            return null
        else
            return rtnArray;
    } catch (e) {
        $c.gus.cfAlertMsg("[f_GetColumnNames] " + e.Description);
    }
}

scwin.ds_selling_oncelldatachange = function (info) {

    //var rowIndex = info.rowIndex;
    let colid = info.colID;
    //var oldValue = info.oldValue;
    //var newValue = info.newValue;

    if (colid == "presumeAmt") {
        scwin.f_ProcPresumeChange();
    } else if (colid == "planAmt") {
        scwin.f_ProcPlanChange();
    }
};

